<template>
  <div class="cart-wrap main">
    <div class="header flex bg-fff">
      <span @click="back" class="red"
        ><i class="iconfont icon-zuojiantou"></i>返回</span
      >
      <span class="f16">购物车</span>
      <span @click="flag = !flag" class="red">{{
        flag ? "完成" : "编辑"
      }}</span>
    </div>
    <ul class="orders">
      <li v-for="(item, index) in cartList" :key="index" class="item">
        <div class="pl-15 pr-15">
          <van-checkbox
            checked-color="red"
            icon-size="16px"
            v-model="item.checked"
          ></van-checkbox>
        </div>
        <img height="100%" :src="item.imgUrl" alt="" />
        <div class="info fg1 flex fdc jc-sb">
          <span class="f16">{{ item.masterName }}</span>
          <p class="flex jc-sb">
            <span class="red f16">
              <i class="iconfont icon-fl-renminbi"></i> {{ item.price / 100 }}
            </span>
            <span class="num">
              <button class="count" @click="updateNum(item, 1)">+</button>
              x{{ item.buyNum }}
              <button class="count" @click="updateNum(item, -1)">-</button>
            </span>
          </p>
        </div>
      </li>
    </ul>
    <div class="bottom flex jc-sb aic bg-fff">
      <van-checkbox
        checked-color="red"
        icon-size="16px"
        v-model="checkAll"
        @click="selectAll"
        >全选</van-checkbox
      >
      <div class="end flex aic">
        <div class="flex cost mr-15">
          <span class="f14">合计:</span>
          <span class="f18 red"
            ><i class="iconfont icon-fl-renminbi"></i> {{ sumPrice }}</span
          >
        </div>
        <button @click="submit" v-if="!flag" id="final">结算</button>
        <button @click="delCart" v-else id="final">删除</button>
      </div>
    </div>
    <Footer></Footer>
  </div>
</template>
<style lang="less">
@import "./cart.less";
</style>
<script>
import Footer from "@/components/Footer";
import $axios from "@/utils/index";
export default {
  components: {
    Footer,
  },
  data() {
    return {
      cartList: [],
      checkAll: false,
      flag: false,
      selectList: [],
    };
  },
  computed: {
    sumPrice() {
      let sum = 0;
      for (let i of this.selectList) {
        sum += (i.price / 100) * i.buyNum;
      }
      return sum.toFixed(2);
    },
  },
  watch: {
    cartList: {
      handler(newList) {
        this.selectList = newList.filter((item) => item.checked);

        if (this.selectList.length === newList.length) {
          this.checkAll = true;
        } else {
          this.checkAll = false;
        }
      },
      deep: true,
    },
  },
  created() {
    this.isLogin();
    this.getList();
  },
  methods: {
    back() {
      this.$router.go(-1);
    },
    selectAll() {
      if (this.checkAll === true) {
        this.cartList.forEach((item) => {
          item.checked = true;
          this.selectList.push(item);
        });
      } else {
        this.cartList.forEach((item) => {
          item.checked = false;
          this.selectList = [];
        });
      }
    },
    async getList() {
      try {
        let res = await $axios.get("cart/all");
        this.cartList = res.list.map((item) => ({ ...item, checked: true }));
      } catch (err) {
        console.log(err);
      }
    },
    async delCart() {
      let cartIdList = this.selectList.map((item) => item.cartId);
      try {
        let res = await $axios.post("cart/del", { cartId: cartIdList });
        // console.log(res)
        this.cartList = this.cartList.filter(
          (item) => !cartIdList.includes(item.cartId)
        );
      } catch (err) {
        console.log(err);
      }
    },
    async updateNum(item, num) {
      try {
        let data = { cartId: item.cartId, buyNum: (item.buyNum += num) };
        let res = await $axios.get("cart/updateNum", data);
        this.$store.commit('setNum',this.$store.state.cart.cartNum+num)
        console.log(res);
      } catch (err) {
        console.log(err);
      } finally {
        if (item.buyNum === 0) {
          try {
            let res = await $axios.get("cart/del", { cartId: item.cartId });
            this.cartList = this.cartList.filter(
              (i) => i.cartId !== item.cartId
            );
          } catch (err) {
            console.log(err);
          }
        }
      }
    },
    async submit() {
      if (!this.selectList.length) {
        this.$toast.fail("请选择商品");
        return false;
      }
      try {
        let cartIdList = this.selectList.map((item) => item.cartId);
        let data = {
          cartId: cartIdList,
          totalMoney: this.sumPrice,
        };
        let res = await $axios.post("preOrder/add", data);
        let { preOrderId } = res.result;
        this.$router.push({
          path: "/preOrder",
          query: { preOrderId },
        });

        // console.log(res)
      } catch (err) {
        console.log(err);
      }
    },
  },
};
</script>